import React from 'react'
import Barcode from 'react-barcode'
import { useNavigate } from 'react-router-dom';

const Codes = () => {
  const [ barcodeValue, setBarcodeValue ] = React.useState('')

  function generateBarcode(length = 13) {
    let barcode = '';
    while (barcode.length < length) {
      barcode += Math.floor(Math.random() * 10); // добавляет цифру от 0 до 9
    }
    return barcode;
  }

  const handleBarcodeChange = (e) => {
    setBarcodeValue(generateBarcode())
    localStorage.setItem('values')
  }

  const Navigate = useNavigate()

  return (
    <div>
      <input type="text" placeholder='Наименование товара' />
      <input type="number" placeholder='Стоимость товара' />
      <button onClick={() => handleBarcodeChange()}>Сгенерировать</button>
      <button onClick={() => Navigate(`/codes-print/${barcodeValue}`)}>Распечатать</button>
      <Barcode value={barcodeValue} />
    </div>
  )
}

export default Codes
